type UserStore struct {
	mu    sync.RWMutex
	users map[string]*User
	seq   int
}

func NewUserStore() *UserStore {
	return &UserStore{users: make(map[string]*User)}
}

func (s *UserStore) Create(email, name string) *User {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.seq++
	id := fmt.Sprintf("user-%d", s.seq)
	now := timestamppb.Now()
	u := &User{
		Id:        id,
		Email:     email,
		Name:      name,
		CreatedAt: now,
		UpdatedAt: now,
		Active:    true,
	}
	s.users[id] = u
	return u
}

func (s *UserStore) Get(id string) (*User, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	u, ok := s.users[id]
	return u, ok
}

func (s *UserStore) Update(id, email, name string) (*User, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()
	u, ok := s.users[id]
	if !ok {
		return nil, false
	}
	if email != "" {
		u.Email = email
	}
	if name != "" {
		u.Name = name
	}
	u.UpdatedAt = timestamppb.Now()
	return u, true
}

func (s *UserStore) Delete(id string) bool {
	s.mu.Lock()
	defer s.mu.Unlock()
	if _, ok := s.users[id]; !ok {
		return false
	}
	delete(s.users, id)
	return true
}

func (s *UserStore) List(pageSize int32) []*User {
	s.mu.RLock()
	defer s.mu.RUnlock()
	if pageSize <= 0 {
		pageSize = 10
	}
	result := make([]*User, 0, pageSize)
	for _, u := range s.users {
		if int32(len(result)) >= pageSize {
			break
		}
		result = append(result, u)
	}
	return result
}

type OrderStore struct {
	mu     sync.RWMutex
	orders map[string]*Order
	seq    int
}

func NewOrderStore() *OrderStore {
	return &OrderStore{orders: make(map[string]*Order)}
}

func (s *OrderStore) Create(userId string, items []*OrderItem) *Order {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.seq++
	id := fmt.Sprintf("order-%d", s.seq)
	var total float64
	for _, item := range items {
		total += item.Price * float64(item.Quantity)
	}
	now := timestamppb.Now()
	o := &Order{
		Id:         id,
		UserId:     userId,
		Items:      items,
		TotalPrice: total,
		Status:     OrderStatus_PENDING,
		CreatedAt:  now,
		UpdatedAt:  now,
	}
	s.orders[id] = o
	return o
}

func (s *OrderStore) Get(id string) (*Order, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	o, ok := s.orders[id]
	return o, ok
}

func (s *OrderStore) UpdateStatus(id string, st OrderStatus) (*Order, bool) {
	s.mu.Lock()
	defer s.mu.Unlock()
	o, ok := s.orders[id]
	if !ok {
		return nil, false
	}
	o.Status = st
	o.UpdatedAt = timestamppb.Now()
	return o, true
}

func (s *OrderStore) ListByUser(userId string, pageSize int32) []*Order {
	s.mu.RLock()
	defer s.mu.RUnlock()
	if pageSize <= 0 {
		pageSize = 10
	}
	result := make([]*Order, 0)
	for _, o := range s.orders {
		if userId != "" && o.UserId != userId {
			continue
		}
		if int32(len(result)) >= pageSize {
			break
		}
		result = append(result, o)
	}
	return result
}

