// --- User Management Service ---
type userManagementServer struct {
	store *UserStore
}

func NewUserManagementServer(store *UserStore) *userManagementServer {
	return &userManagementServer{store: store}
}

func (s *userManagementServer) CreateUser(ctx context.Context, req *CreateUserRequest) (*User, error) {
	if req.Email == "" {
		return nil, status.Error(codes.InvalidArgument, "email is required")
	}
	if req.Name == "" {
		return nil, status.Error(codes.InvalidArgument, "name is required")
	}
	user := s.store.Create(req.Email, req.Name)
	log.Printf("[UserService] Created user: %s (%s)", user.Id, user.Email)
	return user, nil
}

func (s *userManagementServer) GetUser(ctx context.Context, req *GetUserRequest) (*User, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	user, ok := s.store.Get(req.Id)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}
	log.Printf("[UserService] Retrieved user: %s", user.Id)
	return user, nil
}

func (s *userManagementServer) UpdateUser(ctx context.Context, req *UpdateUserRequest) (*User, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	user, ok := s.store.Update(req.Id, req.Email, req.Name)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}
	log.Printf("[UserService] Updated user: %s", user.Id)
	return user, nil
}

func (s *userManagementServer) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*emptypb.Empty, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	if !s.store.Delete(req.Id) {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.Id)
	}
	log.Printf("[UserService] Deleted user: %s", req.Id)
	return &emptypb.Empty{}, nil
}

func (s *userManagementServer) ListUsers(ctx context.Context, req *ListUsersRequest) (*ListUsersResponse, error) {
	users := s.store.List(req.PageSize)
	log.Printf("[UserService] Listed %d users", len(users))
	return &ListUsersResponse{Users: users}, nil
}

