type orderServer struct {
	store     *OrderStore
	userStore *UserStore
}

func NewOrderServer(store *OrderStore, userStore *UserStore) *orderServer {
	return &orderServer{store: store, userStore: userStore}
}

func (s *orderServer) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*Order, error) {
	if req.UserId == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if len(req.Items) == 0 {
		return nil, status.Error(codes.InvalidArgument, "at least one item is required")
	}
	// Verify user exists
	if _, ok := s.userStore.Get(req.UserId); !ok {
		return nil, status.Errorf(codes.NotFound, "user %s not found", req.UserId)
	}
	order := s.store.Create(req.UserId, req.Items)
	log.Printf("[OrderService] Created order: %s for user %s (total: %.2f)", order.Id, order.UserId, order.TotalPrice)
	return order, nil
}

func (s *orderServer) GetOrder(ctx context.Context, req *GetOrderRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	order, ok := s.store.Get(req.Id)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}
	log.Printf("[OrderService] Retrieved order: %s", order.Id)
	return order, nil
}

func (s *orderServer) ListOrders(ctx context.Context, req *ListOrdersRequest) (*ListOrdersResponse, error) {
	orders := s.store.ListByUser(req.UserId, req.PageSize)
	log.Printf("[OrderService] Listed %d orders for user %s", len(orders), req.UserId)
	return &ListOrdersResponse{Orders: orders}, nil
}

func (s *orderServer) UpdateOrderStatus(ctx context.Context, req *UpdateOrderStatusRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	order, ok := s.store.UpdateStatus(req.Id, req.Status)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}
	log.Printf("[OrderService] Updated order %s status to %d", order.Id, order.Status)
	return order, nil
}

func (s *orderServer) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*Order, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	order, ok := s.store.UpdateStatus(req.Id, OrderStatus_CANCELLED)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.Id)
	}
	log.Printf("[OrderService] Cancelled order %s, reason: %s", order.Id, req.Reason)
	return order, nil
}

// --- Payment Service ---
type paymentServer struct {
	store      *PaymentStore
	orderStore *OrderStore
}

func NewPaymentServer(store *PaymentStore, orderStore *OrderStore) *paymentServer {
	return &paymentServer{store: store, orderStore: orderStore}
}

func (s *paymentServer) ProcessPayment(ctx context.Context, req *ProcessPaymentRequest) (*Payment, error) {
	if req.OrderId == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be positive")
	}
	if req.Currency == "" {
		req.Currency = "USD"
	}
	// Verify order exists
	order, ok := s.orderStore.Get(req.OrderId)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "order %s not found", req.OrderId)
	}
	// Check if payment already exists
	if _, exists := s.store.GetByOrder(req.OrderId); exists {
		return nil, status.Errorf(codes.AlreadyExists, "payment already exists for order %s", req.OrderId)
	}
	payment := s.store.Create(req.OrderId, req.UserId, req.Amount, req.Currency, req.Method)
	// Update order status to confirmed
	s.orderStore.UpdateStatus(order.Id, OrderStatus_CONFIRMED)
	log.Printf("[PaymentService] Processed payment %s for order %s (amount: %.2f %s)", payment.Id, payment.OrderId, payment.Amount, payment.Currency)
	return payment, nil
}

func (s *paymentServer) GetPayment(ctx context.Context, req *GetPaymentRequest) (*Payment, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	payment, ok := s.store.Get(req.Id)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}
	log.Printf("[PaymentService] Retrieved payment: %s", payment.Id)
	return payment, nil
}

func (s *paymentServer) GetPaymentByOrder(ctx context.Context, req *GetPaymentByOrderRequest) (*Payment, error) {
	if req.OrderId == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}
	payment, ok := s.store.GetByOrder(req.OrderId)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment for order %s not found", req.OrderId)
	}
	log.Printf("[PaymentService] Retrieved payment by order: %s -> %s", req.OrderId, payment.Id)
	return payment, nil
}

func (s *paymentServer) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*RefundPaymentResponse, error) {
	if req.Id == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	payment, ok := s.store.Refund(req.Id)
	if !ok {
		return nil, status.Errorf(codes.NotFound, "payment %s not found", req.Id)
	}
	refundID := fmt.Sprintf("refund-%s-%d", req.Id, time.Now().UnixNano())
	log.Printf("[PaymentService] Refunded payment %s (refund: %s, reason: %s)", payment.Id, refundID, req.Reason)
	return &RefundPaymentResponse{
		Payment:  payment,
		RefundId: refundID,
	}, nil
}

func (s *paymentServer) ListPayments(ctx context.Context, req *ListPaymentsRequest) (*ListPaymentsResponse, error) {
	payments := s.store.ListByUser(req.UserId, req.PageSize)
	log.Printf("[PaymentService] Listed %d payments for user %s", len(payments), req.UserId)
	return &ListPaymentsResponse{Payments: payments}, nil
}

