// ============================================================================
// Logging interceptor for development
// ============================================================================

func loggingUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (interface{}, error) {
	start := time.Now()
	log.Printf("[DEV] --> %s", info.FullMethod)

	resp, err := handler(ctx, req)

	duration := time.Since(start)
	if err != nil {
		st, _ := status.FromError(err)
		log.Printf("[DEV] <-- %s [%s] %v (%s)", info.FullMethod, st.Code(), st.Message(), duration)
	} else {
		log.Printf("[DEV] <-- %s [OK] (%s)", info.FullMethod, duration)
	}

	return resp, err
}

// ============================================================================
// Recovery interceptor
// ============================================================================

func recoveryUnaryInterceptor(
	ctx context.Context,
	req interface{},
	info *grpc.UnaryServerInfo,
	handler grpc.UnaryHandler,
) (resp interface{}, err error) {
	defer func() {
		if r := recover(); r != nil {
			log.Printf("[RECOVERY] Panic in %s: %v", info.FullMethod, r)
			err = status.Errorf(codes.Internal, "internal server error")
		}
	}()
	return handler(ctx, req)
}

// ============================================================================
// Main
// ============================================================================

func main() {
	port := ":50051"

	lis, err := net.Listen("tcp", port)
	if err != nil {
		log.Fatalf("Failed to listen on %s: %v", port, err)
	}

	// Create gRPC server with interceptors for development
	grpcServer := grpc.NewServer(
		grpc.ChainUnaryInterceptor(
			recoveryUnaryInterceptor,
			loggingUnaryInterceptor,
		),
	)

	// Initialize stores
	userStore := NewUserStore()
	orderStore := NewOrderStore()
	paymentStore := NewPaymentStore()

	// Seed some development data
	seedDevData(userStore, orderStore, paymentStore)

	// Register services
	userSrv := NewUserManagementServer(userStore)
	orderSrv := NewOrderServer(orderStore, userStore)
	paymentSrv := NewPaymentServer(paymentStore, orderStore)

	registerUserManagementService(grpcServer, userSrv)
	registerOrderService(grpcServer, orderSrv)
	registerPaymentService(grpcServer, paymentSrv)

	// Enable reflection for development and testing
	// This allows tools like grpcurl, grpcui, and Postman to discover services
	reflection.Register(grpcServer)

	log.Println("============================================================")
	log.Println("  Microservices Development gRPC Server")
	log.Println("============================================================")
	log.Printf("  Listening on %s", port)
	log.Println("  Reflection: ENABLED (development mode)")
	log.Println("")
	log.Println("  Registered services:")
	log.Println("    - microservices.UserManagementService")
	log.Println("      * CreateUser, GetUser, UpdateUser, DeleteUser, ListUsers")
	log.Println("    - microservices.OrderService")
	log.Println("      * CreateOrder, GetOrder, ListOrders, UpdateOrderStatus, CancelOrder")
	log.Println("    - microservices.PaymentService")
	log.Println("      * ProcessPayment, GetPayment, GetPaymentByOrder, RefundPayment, ListPayments")
	log.Println("")
	log.Println("  Test with grpcurl:")
	log.Println("    grpcurl -plaintext localhost:50051 list")
	log.Println("    grpcurl -plaintext localhost:50051 describe microservices.UserManagementService")
	log.Println("============================================================")

	if err := grpcServer.Serve(lis); err != nil {
		log.Fatalf("Failed to serve: %v", err)
	}
}

func seedDevData(userStore *UserStore, orderStore *OrderStore, paymentStore *PaymentStore) {
	log.Println("[SEED] Populating development data...")

	// Create sample users
	u1 := userStore.Create("alice@example.com", "Alice Johnson")
	u2 := userStore.Create("bob@example.com", "Bob Smith")
	u3 := userStore.Create("charlie@example.com", "Charlie Brown")

	log.Printf("[SEED] Created users: %s, %s, %s", u1.Id, u2.Id, u3.Id)

	// Create sample orders
	o1 := orderStore.Create(u1.Id, []*OrderItem{
		{ProductId: "prod-1", Name: "Laptop", Quantity: 1, Price: 999.99},
		{ProductId: "prod-2", Name: "Mouse", Quantity: 2, Price: 29.99},
	})
	o2 := orderStore.Create(u2.Id, []*OrderItem{
		{ProductId: "prod-3", Name: "Keyboard", Quantity: 1, Price: 149.99},
	})
	o3 := orderStore.Create(u1.Id, []*OrderItem{
		{ProductId: "prod-4", Name: "Monitor", Quantity: 1, Price: 499.99},
		{ProductId: "prod-5", Name: "USB Cable", Quantity: 3, Price: 9.99},
	})

	log.Printf("[SEED] Created orders: %s, %s, %s", o1.Id, o2.Id, o3.Id)

	// Create sample payments
	p1 := paymentStore.Create(o1.Id, u1.Id, o1.TotalPrice, "USD", PaymentMethod_CREDIT_CARD)
	p2 := paymentStore.Create(o2.Id, u2.Id, o2.TotalPrice, "USD", PaymentMethod_DIGITAL_WALLET)
	orderStore.UpdateStatus(o1.Id, OrderStatus_CONFIRMED)
	orderStore.UpdateStatus(o2.Id, OrderStatus_CONFIRMED)

	log.Printf("[SEED] Created payments: %s, %s", p1.Id, p2.Id)
	log.Println("[SEED] Development data seeded successfully")
}